"use client";

import { useState, useRef, useCallback, useId, useEffect } from "react";
import { SendHorizontal, Sparkles, BrainCircuit } from "lucide-react";

interface Message {
  role: "user" | "assistant";
  content: string;
}

export default function ChatPage() {
  const [messages, setMessages] = useState<Message[]>([]);
  const [input, setInput] = useState("");
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState<string | null>(null);
  const messagesEndRef = useRef<HTMLDivElement>(null);
  const textareaId = useId();
  const suggestionDelayClass = [
    "animate-delay-200",
    "animate-delay-300",
    "animate-delay-400",
    "animate-delay-500",
  ];
  const typingDelayClass = ["animate-delay-0", "animate-delay-150", "animate-delay-300"];

  useEffect(() => {
    messagesEndRef.current?.scrollIntoView({ behavior: "smooth" });
  }, [messages]);

  const sendMessage = useCallback(async () => {
    const text = input.trim();
    if (!text || loading) return;

    setInput("");
    setError(null);

    const newMessages: Message[] = [...messages, { role: "user", content: text }];
    setMessages(newMessages);
    setLoading(true);

    try {
      const res = await fetch("/api/ai/chat", {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({ messages: newMessages }),
      });

      if (!res.ok) {
        const err = await res.json().catch(() => ({}));
        throw new Error(
          (err as { error?: string }).error ?? `Erro ${res.status}`
        );
      }

      const json = (await res.json()) as { data: { reply: string } };
      setMessages([
        ...newMessages,
        { role: "assistant", content: json.data.reply },
      ]);
    } catch (e) {
      setError(e instanceof Error ? e.message : "Erro desconhecido");
    } finally {
      setLoading(false);
    }
  }, [input, messages, loading]);

  const handleKeyDown = (e: React.KeyboardEvent) => {
    if (e.key === "Enter" && !e.shiftKey) {
      e.preventDefault();
      sendMessage();
    }
  };

  return (
    <div className="flex flex-col h-[calc(100vh-80px)] md:h-[calc(100vh-64px)] w-full max-w-5xl mx-auto md:my-8 relative z-10 animate-[fadeUp_0.5s_ease-out_backwards]">
      
      {/* Luxury Chat Container */}
      <div className="flex-1 flex flex-col glass-panel rounded-none md:rounded-3xl overflow-hidden border-x-0 md:border-x border-y-0 md:border-y border-[var(--color-border-subtle)] md:shadow-[0_20px_60px_rgba(0,0,0,0.5)] bg-[var(--color-bg-base)]/80 relative">
        
        {/* Ambient Top Glow */}
        <div className="absolute top-0 inset-x-0 h-40 bg-gradient-to-b from-[var(--color-brand)]/5 to-transparent pointer-events-none" />
        
        {/* Header */}
        <header className="px-6 py-5 border-b border-[var(--color-border-subtle)] shrink-0 bg-[var(--color-surface)]/50 backdrop-blur-md relative z-20 flex flex-col md:flex-row md:items-center justify-between gap-4">
          <div className="flex items-center gap-4">
            <div className="w-12 h-12 rounded-2xl bg-gradient-to-br from-[var(--color-surface-hover)] to-[var(--color-surface)] flex items-center justify-center border border-[var(--color-border-subtle)] shadow-[0_4px_20px_rgba(0,0,0,0.2)]">
              <Sparkles size={20} className="text-[var(--color-brand)] animate-pulse-slow" />
            </div>
            <div>
              <h1 className="font-[family-name:var(--font-display)] text-[22px] font-medium text-[var(--color-text-primary)] tracking-tight">
                Concierge AI
              </h1>
              <p className="text-[12px] text-[var(--color-text-secondary)] mt-0.5 tracking-wide uppercase font-semibold flex items-center gap-2">
                <span className="w-1.5 h-1.5 rounded-full bg-[var(--color-brand)] animate-pulse" />
                Online &bull; <span className="text-[var(--color-text-muted)]">100% Privado</span>
              </p>
            </div>
          </div>
        </header>

        {/* Messages Area */}
        <div className="flex-1 overflow-y-auto px-4 md:px-8 py-8 flex flex-col gap-6 relative z-10 scrollbar-custom">
          {messages.length === 0 && (
            <div className="flex-1 flex items-center justify-center">
              <div className="text-center max-w-md w-full p-8 rounded-3xl bg-[var(--color-surface)] border border-[var(--color-border-subtle)] shadow-[0_10px_40px_rgba(0,0,0,0.2)]">
                <div className="w-16 h-16 rounded-full bg-[var(--color-brand)]/10 text-[var(--color-brand)] flex items-center justify-center mx-auto mb-6 border border-[var(--color-brand)]/20">
                  <BrainCircuit size={28} strokeWidth={1.5} />
                </div>
                <h2 className="font-[family-name:var(--font-display)] text-2xl text-[var(--color-text-primary)] font-medium mb-3 tracking-tight">
                  Como posso apoiar você hoje?
                </h2>
                <p className="text-[14px] text-[var(--color-text-secondary)] leading-relaxed mb-8 px-2 font-light">
                  Estou aqui para ouvir. Pergunte sobre exercícios de respiração, técnicas de
                  mindfulness, ou apenas reflita sobre o que está sentindo no momento.
                </p>
                <div className="flex flex-col gap-3">
                  {[
                    "Como posso lidar com um pico de ansiedade?",
                    "Me guie por um momento de respiração",
                    "Estou me sentindo sobrecarregado hoje...",
                    "Quero organizar meus pensamentos"
                  ].map((suggestion, i) => (
                    <button
                      key={suggestion}
                      type="button"
                      onClick={() => setInput(suggestion)}
                      className={`animate-[fadeUp_0.4s_ease-out_backwards] py-3.5 px-5 rounded-xl text-[13.5px] text-left transition-all duration-300 bg-[var(--color-surface-hover)] border border-[var(--color-border-subtle)] text-[var(--color-text-primary)] hover:border-[var(--color-brand)]/40 hover:bg-[var(--color-brand)]/5 hover:text-[var(--color-brand)] w-full shadow-sm ${suggestionDelayClass[i] ?? ""}`}
                    >
                      "{suggestion}"
                    </button>
                  ))}
                </div>
              </div>
            </div>
          )}

          {messages.map((msg, i) => {
            const isUser = msg.role === "user";
            return (
              <div
                key={i}
                className={`flex ${isUser ? "justify-end" : "justify-start"} animate-[fadeUp_0.3s_ease-out_backwards]`}
              >
                {!isUser && (
                  <div className="w-8 h-8 rounded-full bg-[var(--color-surface-hover)] border border-[var(--color-border-subtle)] flex items-center justify-center shrink-0 mr-3 mt-1 shadow-sm">
                    <Sparkles size={14} className="text-[var(--color-brand)]" />
                  </div>
                )}
                
                <div
                  className={`max-w-[85%] md:max-w-[75%] px-5 py-4 text-[14.5px] leading-relaxed whitespace-pre-wrap ${
                    isUser
                      ? "bg-[var(--color-brand)] text-[var(--color-bg-base)] rounded-2xl rounded-tr-[4px] shadow-[0_4px_20px_rgba(82,183,136,0.15)] font-medium"
                      : "bg-[var(--color-surface)]/80 text-[var(--color-text-primary)] font-light border border-[var(--color-border-subtle)] rounded-2xl rounded-tl-[4px] shadow-sm backdrop-blur-sm"
                  }`}
                >
                  {msg.content}
                </div>
              </div>
            );
          })}

          {error && (
            <div className="px-5 py-4 bg-red-500/10 border border-red-500/20 rounded-xl text-red-400 text-[13px] animate-[fadeUp_0.2s_ease-out] font-medium mx-auto max-w-sm text-center">
              Não foi possível conectar. Revise sua conexão e tente novamente.
            </div>
          )}

          {loading && (
            <div className="flex justify-start animate-[fadeUp_0.3s_ease-out_backwards]">
              <div className="w-8 h-8 rounded-full bg-[var(--color-surface-hover)] border border-[var(--color-border-subtle)] flex items-center justify-center shrink-0 mr-3 mt-1 shadow-sm">
                <Sparkles size={14} className="text-[var(--color-brand)] opacity-50" />
              </div>
              <div className="px-5 py-4 bg-[var(--color-surface)] border border-[var(--color-border-subtle)] rounded-2xl rounded-tl-[4px] flex gap-2 items-center shadow-sm">
                {[0, 1, 2].map((n) => (
                  <span
                    key={n}
                    className={`w-1.5 h-1.5 rounded-full bg-[var(--color-brand)] opacity-40 animate-pulse ${typingDelayClass[n] ?? ""}`}
                  />
                ))}
              </div>
            </div>
          )}

          <div ref={messagesEndRef} />
        </div>

        {/* Input Area */}
        <div className="px-4 md:px-6 py-5 border-t border-[var(--color-border-subtle)] bg-[var(--color-bg-elevated)] shrink-0 relative z-20">
          <div className="flex gap-3 items-end max-w-4xl mx-auto">
            <label htmlFor={textareaId} className="sr-only">
              Sua mensagem
            </label>
            <div className="flex-1 relative">
              <textarea
                id={textareaId}
                value={input}
                onChange={(e) => setInput(e.target.value)}
                onKeyDown={handleKeyDown}
                placeholder="Como você está se sentindo?"
                rows={1}
                className="w-full px-5 py-[14px] rounded-xl bg-[var(--color-surface-hover)] border border-[var(--color-border-subtle)] text-[var(--color-text-primary)] font-[family-name:var(--font-sans)] text-[14.5px] leading-relaxed resize-none outline-none max-h-[120px] scrollbar-custom focus:border-[var(--color-brand)]/50 focus:bg-[var(--color-surface)] focus:ring-1 focus:ring-[var(--color-brand)]/30 transition-all placeholder:text-[var(--color-text-muted)] placeholder:font-light shadow-inner"
              />
            </div>
            
            <button
              type="button"
              onClick={sendMessage}
              disabled={loading || !input.trim()}
              className="p-[14px] rounded-xl flex items-center justify-center transition-all duration-300 shrink-0 group 
                disabled:opacity-50 disabled:cursor-not-allowed
                bg-[var(--color-brand)] text-[var(--color-bg-base)] 
                hover:bg-[var(--color-brand-hover)] border border-[var(--color-brand)]/20 shadow-[0_4px_15px_rgba(82,183,136,0.25)] hover:shadow-[0_4px_25px_rgba(82,183,136,0.4)]
                active:scale-95"
            >
              <SendHorizontal strokeWidth={2.5} className="w-[18px] h-[18px] group-hover:translate-x-0.5 group-hover:-translate-y-0.5 transition-transform duration-300" />
              <span className="sr-only">Enviar mensagem</span>
            </button>
          </div>
          <div className="text-[10px] text-[var(--color-text-muted)] mt-3.5 text-center uppercase tracking-[0.15em] font-semibold">
            A IA apoia, mas não substitui ajuda clínica. CVV: 188.
          </div>
        </div>
      </div>
    </div>
  );
}
